query:
_view=sumologic_search_usage_per_query 
//| where execution_duration_ms > 30000
//not query_type = view*
not query_type = sumo*
| where data_scanned_bytes > (100 * 1G)

//| where scanned_partition_count >5
| sum(data_scanned_bytes) as bytes by query_type,scanned_partition_count

| toint(ceil(scanned_partition_count/5) * 5) as part_range
| sum(bytes) as bytes by part_range,query_type
| transpose row query_type column part_range
